/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(PurchLine), DataEventType::Inserted)]
public static void PurchLine_onInserted(Common _sender, DataEventArgs _e)
{
    PurchLine						purchLine  = _sender as PurchLine;
    PurchTable						purchTable = purchLine.purchTable();
    SalesLine						salesLineIC;
    FWFTextBlockEventHandler_Setup	handler;

    if (purchTable.InterCompanySalesId &&
        purchLine.SkipUpdate   != InterCompanySkipUpdate::InterCompany &&
        purchLine.SkipUpdate   != InterCompanySkipUpdate::Both)
    {
        changeCompany(purchTable.InterCompanyCompanyId)
        {
            salesLineIC = SalesLine::findInventTransId(purchLine.InterCompanyInventTransId);
            handler = FWFTextBlockEventHandler_Setup::construct();
            handler.parmTargetRecord(salesLineIC);
            handler.parmEventType(EventLogType::Update);
            handler.run();
        }
    }
}
